        uint256 usdcAmount,
        uint256 dogeAmount,
        uint256 subscribeTime,
        bool isActive,
        bool hasClaimed,
        bool hasRefunded
    ) {
        Subscription storage sub = userSubscriptions[user][candidateId];
        return (sub.usdcAmount, sub.dogeAmount, sub.subscribeTime, sub.isActive, sub.hasClaimed, sub.hasRefunded);
    }

